// coches.net – enriquecer: ficha HTML → JSON-LD (Car) + __INITIAL_PROPS__.ad → UPDATE
const row = $('Loop: oferta por oferta').item.json;
const dbId = String(row.id || '');
const httpOut = $input.item.json;
const html = typeof httpOut === 'string' ? httpOut : String(httpOut.data || httpOut.body || '');

if (!dbId) return [{ json: { id: null, hasUpdates: false, updateSql: null } }];

function esc(v) {
  if (v === null || v === undefined || v === '') return 'NULL';
  if (typeof v === 'number') return isNaN(v) ? 'NULL' : String(v);
  return "'" + String(v).replace(/'/g, "''") + "'";
}
function normalizeBody(raw) {
  var s = String(raw || '').toLowerCase();
  if (!s) return '';
  if (s.indexOf('suv') !== -1 || s.indexOf('4x4') !== -1 || s.indexOf('todo') !== -1) return 'SUV';
  if (s.indexOf('pick') !== -1) return 'Pick Up';
  if (s.indexOf('furgon') !== -1 || s.indexOf('van') !== -1 || s.indexOf('comercial') !== -1) return 'Furgoneta';
  if (s.indexOf('familiar') !== -1 || s.indexOf('estate') !== -1 || s.indexOf('combi') !== -1) return 'Familiar';
  if (s.indexOf('monovolum') !== -1 || s.indexOf('mpv') !== -1) return 'Monovolumen';
  if (s.indexOf('coup') !== -1) return 'Coupé';
  if (s.indexOf('cabrio') !== -1 || s.indexOf('descapotable') !== -1 || s.indexOf('convert') !== -1) return 'Cabrio';
  if (s.indexOf('pequeñ') !== -1 || s.indexOf('pequen') !== -1 || s.indexOf('compact') !== -1 || s.indexOf('ciudad') !== -1 || s.indexOf('utilitario') !== -1) return 'Compacto';
  if (s.indexOf('berlina') !== -1 || s.indexOf('sedan') !== -1 || s.indexOf('turismo') !== -1 || s.indexOf('hatchback') !== -1) return 'Berlina';
  return raw || '';
}
function normalizeGear(raw) {
  var s = String(raw || '').toLowerCase();
  if (s.indexOf('autom') !== -1 || s.indexOf('dct') !== -1 || s.indexOf('cvt') !== -1 || s.indexOf('dsg') !== -1) return 'Automatica';
  if (s.indexOf('manual') !== -1) return 'Manual';
  return '';
}
function normalizeTraction(raw) {
  var s = String(raw || '').toLowerCase();
  if (!s) return '';
  if (s.indexOf('4x4') !== -1 || s.indexOf('4wd') !== -1 || s.indexOf('awd') !== -1 || s.indexOf('all') !== -1 || s.indexOf('four') !== -1 || s.indexOf('total') !== -1 || s.indexOf('integral') !== -1) return '4x4';
  if (s.indexOf('rear') !== -1 || s.indexOf('rwd') !== -1 || s.indexOf('tras') !== -1) return 'Trasera';
  if (s.indexOf('front') !== -1 || s.indexOf('fwd') !== -1 || s.indexOf('del') !== -1) return 'Delantera';
  return '';
}
function normalizeLabel(raw) {
  var s = String(raw || '').toLowerCase().trim();
  if (!s) return '';
  if (s === 'zero' || s === 'cero' || s === '0' || s.indexOf('0 emis') !== -1) return '0 Emisiones';
  if (s.indexOf('eco') !== -1 || s === 'e') return 'ECO';
  if (s === 'c' || s === 'green') return 'C';
  if (s === 'b' || s === 'yellow') return 'B';
  return String(raw).toUpperCase();
}

// ── JSON-LD (Car) ──────────────────────────────────────────────
var veh = {};
try {
  var blocks = [...html.matchAll(/<script[^>]*type="application\/ld\+json"[^>]*>([\s\S]*?)<\/script>/g)];
  for (var bi = 0; bi < blocks.length; bi++) {
    var o = null; try { o = JSON.parse(blocks[bi][1]); } catch (e) {}
    if (!o) continue;
    var arr = o['@graph'] || [o];
    for (var ai = 0; ai < arr.length; ai++) {
      var x = arr[ai];
      if (x && (x['@type'] === 'Car' || x['@type'] === 'Vehicle' || x.bodyType || x.numberOfDoors)) veh = x;
    }
  }
} catch (e) {}

// ── __INITIAL_PROPS__.ad ───────────────────────────────────────
var ad = {};
try {
  var mk = 'window.__INITIAL_PROPS__ = JSON.parse(';
  var i = html.indexOf(mk);
  if (i !== -1) {
    var j = i + mk.length, k = j + 1, e = false;
    for (; k < html.length; k++) { var c = html[k]; if (e) e = false; else if (c === '\\') e = true; else if (c === '"') break; }
    var props = JSON.parse(JSON.parse(html.slice(j, k + 1)));
    ad = props.ad || {};
  }
} catch (e) {}

// ── Campos ─────────────────────────────────────────────────────
var color = veh.color || '';
var body_type = normalizeBody(veh.bodyType || (ad.bodyType || ''));
var doors = (veh.numberOfDoors != null) ? parseInt(veh.numberOfDoors, 10) : null;
var seats = (veh.seatingCapacity != null) ? parseInt(veh.seatingCapacity, 10) : null;
var transmission = normalizeGear(veh.vehicleTransmission || ad.transmissionType || '');
var traction = normalizeTraction(ad.traction || '');
var environmental_label = normalizeLabel(ad.environmentalLabel || '');
var version = ad.version || '';
var warranty_months = (ad.warrantyMonths != null && ad.warrantyMonths > 0) ? parseInt(ad.warrantyMonths, 10) : null;

var displacement = null, consumption = null, power_cv = null;
var eng = veh.vehicleEngine || {};
if (eng.engineDisplacement && eng.engineDisplacement.value) {
  var dd = parseInt(String(eng.engineDisplacement.value).replace(/[.,\s]/g, ''), 10);
  if (!isNaN(dd) && dd > 0) displacement = dd;
}
if (eng.enginePower && eng.enginePower.value) {
  var pc = parseInt(eng.enginePower.value, 10);
  if (!isNaN(pc) && pc > 0) power_cv = pc;
}
if (veh.fuelEfficiency && veh.fuelEfficiency.value != null) {
  var cs = parseFloat(veh.fuelEfficiency.value);
  if (!isNaN(cs) && cs > 0) consumption = cs;
}
var power_kw = power_cv ? Math.round(power_cv / 1.35962) : null;

// ── SQL (COALESCE: solo rellena vacíos) ────────────────────────
var sets = [];
if (color)                  sets.push("color = COALESCE(NULLIF(color,''), " + esc(color) + ")");
if (body_type)              sets.push("body_type = COALESCE(NULLIF(body_type,''), " + esc(body_type) + ")");
if (doors && doors > 0)     sets.push("doors = COALESCE(NULLIF(doors,0), " + doors + ")");
if (seats && seats > 0)     sets.push("seats = COALESCE(NULLIF(seats,0), " + seats + ")");
if (transmission)           sets.push("transmission = COALESCE(NULLIF(transmission,''), " + esc(transmission) + ")");
if (traction)               sets.push("traction = COALESCE(NULLIF(traction,''), " + esc(traction) + ")");
if (environmental_label)    sets.push("environmental_label = COALESCE(NULLIF(environmental_label,''), " + esc(environmental_label) + ")");
if (version)                sets.push("version = COALESCE(NULLIF(version,''), " + esc(version) + ")");
if (warranty_months)        sets.push("warranty_months = COALESCE(NULLIF(warranty_months,0), " + warranty_months + ")");
if (displacement)           sets.push("displacement = COALESCE(NULLIF(displacement,''), '" + displacement + "')");
if (consumption)            sets.push("consumption = COALESCE(NULLIF(consumption,0), " + consumption + ")");
if (power_cv)               sets.push("power_cv = COALESCE(NULLIF(power_cv,0), " + power_cv + ")");
if (power_kw)               sets.push("power_kw = COALESCE(NULLIF(power_kw,0), " + power_kw + ")");

sets.push('enrich_tried_at = NOW()');

var updateSql = 'UPDATE moveadvisor_market_offers SET ' + sets.join(', ') + ', updated_at = NOW() WHERE id = ' + esc(dbId);

return [{ json: {
  id: dbId, hasUpdates: true, updateSql: updateSql,
  extracted: { color: color, body_type: body_type, doors: doors, seats: seats, transmission: transmission, traction: traction, environmental_label: environmental_label, version: version, displacement: displacement, consumption: consumption, power_cv: power_cv }
} }];
